class Solution {
    public String crackSafe(int n, int k) {
        if (n == 1 && k == 1) return "0";
        StringBuilder sb = new StringBuilder();
        int total = (int) Math.pow(k, n);
        boolean[] seen = new boolean[total];
        int node = 0;
        for (int i = 0; i < n - 1; i++) sb.append('0');
        dfs(node, k, n, total, seen, sb);
        return sb.toString();
    }

    private void dfs(int node, int k, int n, int total, boolean[] seen, StringBuilder sb) {
        for (int i = 0; i < k; i++) {
            int nei = (node * k + i) % total;
            if (!seen[nei]) {
                seen[nei] = true;
                dfs(nei, k, n, total, seen, sb);
                sb.append((char) ('0' + i));
            }
        }
    }
}
